     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState, jjrg_Pace as Pace};
    13→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    14→use serde::Serialize;
    15→use std::fs;
    16→
    17→// ============================================================================
    18→// Muster - List all Heats with summary information
    19→// ============================================================================
    20→
    21→/// Arguments for muster command
    22→#[derive(Debug)]
    23→pub struct jjrq_MusterArgs {
    24→    pub file: std::path::PathBuf,
    25→    pub status: Option<String>,
    26→}
    27→
    28→/// Run the muster command - list Heats as TSV
    29→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    30→    let gallops = match Gallops::jjrg_load(&args.file) {
    31→        Ok(g) => g,
    32→        Err(e) => {
    33→            eprintln!("jjx_muster: error: {}", e);
    34→            return 1;
    35→        }
    36→    };
    37→
    38→    // Collect heats with status info for sorting
    39→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    40→
    41→    // Apply status filter if specified
    42→    if let Some(ref filter_status) = args.status {
    43→        let filter_lowercase = filter_status.to_lowercase();
    44→        heats_by_status.retain(|(_, heat)| {
    45→            let heat_status_str = match heat.status {
    46→                HeatStatus::Racing => "racing",
    47→                HeatStatus::Stabled => "stabled",
    48→                HeatStatus::Retired => "retired",
    49→            };
    50→            heat_status_str == filter_lowercase
    51→        });
    52→    }
    53→
    54→    // Sort: racing first, then stabled, then retired
    55→    heats_by_status.sort_by(|a, b| {
    56→        let a_status_order = match a.1.status {
    57→            HeatStatus::Racing => 0,
    58→            HeatStatus::Stabled => 1,
    59→            HeatStatus::Retired => 2,
    60→        };
    61→        let b_status_order = match b.1.status {
    62→            HeatStatus::Racing => 0,
    63→            HeatStatus::Stabled => 1,
    64→            HeatStatus::Retired => 2,
    65→        };
    66→        a_status_order.cmp(&b_status_order)
    67→    });
    68→
    69→    for (key, heat) in heats_by_status {
    70→        let total_pace_count = heat.paces.len();
    71→
    72→        // Count actionable paces (rough or bridled)
    73→        let remaining_count = heat.paces.values().filter(|pace| {
    74→            if let Some(tack) = pace.tacks.first() {
    75→                matches!(tack.state, PaceState::Rough | PaceState::Bridled)
    76→            } else {
    77→                false
    78→            }
    79→        }).count();
    80→
    81→        let status_str = match heat.status {
    82→            HeatStatus::Racing => "racing",
    83→            HeatStatus::Stabled => "stabled",
    84→            HeatStatus::Retired => "retired",
    85→        };
    86→
    87→        println!("{}\t{}\t{}\t{}\t{}", key, heat.silks, status_str, remaining_count, total_pace_count);
    88→    }
    89→
    90→    0
    91→}
