    93→// ============================================================================
    94→// Saddle - Return context needed to saddle up on a Heat
    95→// ============================================================================
    96→
    97→/// Arguments for saddle command
    98→#[derive(Debug)]
    99→pub struct jjrq_SaddleArgs {
   100→    pub file: std::path::PathBuf,
   101→    pub firemark: Firemark,
   102→}
   103→
   104→/// Output structure for saddle command
   105→#[derive(Serialize)]
   106→pub(crate) struct zjjrq_SaddleOutput {
   107→    pub(crate) heat_silks: String,
   108→    pub(crate) paddock_file: String,
   109→    pub(crate) paddock_content: String,
   110→    #[serde(skip_serializing_if = "Option::is_none")]
   111→    pub(crate) pace_coronet: Option<String>,
   112→    #[serde(skip_serializing_if = "Option::is_none")]
   113→    pub(crate) pace_silks: Option<String>,
   114→    #[serde(skip_serializing_if = "Option::is_none")]
   115→    pub(crate) pace_state: Option<String>,
   116→    #[serde(skip_serializing_if = "Option::is_none")]
   117→    pub(crate) spec: Option<String>,
   118→    #[serde(skip_serializing_if = "Option::is_none")]
   119→    pub(crate) direction: Option<String>,
   120→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
   121→}
   122→
   123→/// Run the saddle command - return Heat context
   124→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   125→    let gallops = match Gallops::jjrg_load(&args.file) {
   126→        Ok(g) => g,
   127→        Err(e) => {
   128→            eprintln!("jjx_saddle: error: {}", e);
   129→            return 1;
   130→        }
   131→    };
   132→
   133→    let heat_key = args.firemark.jjrf_display();
   134→    let heat = match gallops.heats.get(&heat_key) {
   135→        Some(h) => h,
   136→        None => {
   137→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   138→            return 1;
   139→        }
   140→    };
   141→
   142→    // Check if heat is stabled (cannot saddle stabled heat)
   143→    if heat.status == HeatStatus::Stabled {
   144→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   145→        return 1;
   146→    }
   147→
   148→    // Read paddock file content
   149→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   150→        Ok(content) => content,
   151→        Err(e) => {
   152→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   153→            return 1;
   154→        }
   155→    };
   156→
   157→    // Get recent steeplechase entries
   158→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   159→        firemark: args.firemark.jjrf_as_str().to_string(),
   160→        limit: 10,
   161→    }).unwrap_or_default();
   162→
   163→    // Find first actionable pace (rough or bridled)
   164→    let mut output = zjjrq_SaddleOutput {
   165→        heat_silks: heat.silks.clone(),
   166→        paddock_file: heat.paddock_file.clone(),
   167→        paddock_content,
   168→        pace_coronet: None,
   169→        pace_silks: None,
   170→        pace_state: None,
   171→        spec: None,
   172→        direction: None,
   173→        recent_work,
   174→    };
   175→
   176→    for coronet_key in &heat.order {
   177→        if let Some(pace) = heat.paces.get(coronet_key) {
   178→            if let Some(tack) = pace.tacks.first() {
   179→                match tack.state {
   180→                    PaceState::Rough | PaceState::Bridled => {
   181→                        output.pace_coronet = Some(coronet_key.clone());
   182→                        output.pace_silks = Some(tack.silks.clone());
   183→                        output.pace_state = Some(match tack.state {
   184→                            PaceState::Rough => "rough".to_string(),
   185→                            PaceState::Bridled => "bridled".to_string(),
   186→                            _ => unreachable!(),
   187→                        });
   188→                        output.spec = Some(tack.text.clone());
   189→                        if tack.state == PaceState::Bridled {
   190→                            output.direction = tack.direction.clone();
   191→                        }
   192→                        break;
   193→                    }
   194→                    _ => continue,
   195→                }
   196→            }
   197→        }
   198→    }
   199→
   200→    // Output JSON
   201→    match serde_json::to_string_pretty(&output) {
   202→        Ok(json) => {
   203→            println!("{}", json);
   204→            0
   205→        }
   206→        Err(e) => {
   207→            eprintln!("jjx_saddle: error serializing output: {}", e);
   208→            1
   209→        }
   210→    }
   211→}
