   213→// ============================================================================
   214→// Parade - Display comprehensive Heat status for project review
   215→// ============================================================================
   216→
   217→/// Output format modes for parade command
   218→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   219→pub enum jjrq_ParadeFormat {
   220→    /// One line per pace: [state] silks (₢coronet)
   221→    Overview,
   222→    /// Numbered list: N. [state] silks (₢coronet)
   223→    Order,
   224→    /// Full tack text for one pace (requires --pace)
   225→    Detail,
   226→    /// Paddock + all paces with tack text (default)
   227→    #[default]
   228→    Full,
   229→}
   230→
   231→/// Arguments for parade command
   232→#[derive(Debug)]
   233→pub struct jjrq_ParadeArgs {
   234→    pub file: std::path::PathBuf,
   235→    pub firemark: Firemark,
   236→    pub format: jjrq_ParadeFormat,
   237→    pub pace: Option<String>,
   238→    pub remaining: bool,
   239→}
   240→
   241→/// Run the parade command - display comprehensive Heat status
   242→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   243→    // Validate: detail format requires --pace
   244→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   245→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   246→        return 1;
   247→    }
   248→
   249→    let gallops = match Gallops::jjrg_load(&args.file) {
   250→        Ok(g) => g,
   251→        Err(e) => {
   252→            eprintln!("jjx_parade: error: {}", e);
   253→            return 1;
   254→        }
   255→    };
   256→
   257→    let heat_key = args.firemark.jjrf_display();
   258→    let heat = match gallops.heats.get(&heat_key) {
   259→        Some(h) => h,
   260→        None => {
   261→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   262→            return 1;
   263→        }
   264→    };
   265→
   266→    match args.format {
   267→        jjrq_ParadeFormat::Overview => {
   268→            for coronet_key in &heat.order {
   269→                if let Some(pace) = heat.paces.get(coronet_key) {
   270→                    if let Some(tack) = pace.tacks.first() {
   271→                        // Skip complete/abandoned if --remaining
   272→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   273→                            continue;
   274→                        }
   275→                        let state_str = zjjrq_pace_state_str(&tack.state);
   276→                        println!("[{}] {} ({})", state_str, tack.silks, coronet_key);
   277→                    }
   278→                }
   279→            }
   280→        }
   281→        jjrq_ParadeFormat::Order => {
   282→            let mut num = 0;
   283→            for coronet_key in &heat.order {
   284→                if let Some(pace) = heat.paces.get(coronet_key) {
   285→                    if let Some(tack) = pace.tacks.first() {
   286→                        // Skip complete/abandoned if --remaining
   287→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   288→                            continue;
   289→                        }
   290→                        num += 1;
   291→                        let state_str = zjjrq_pace_state_str(&tack.state);
   292→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   293→                    }
   294→                }
   295→            }
   296→        }
   297→        jjrq_ParadeFormat::Detail => {
   298→            let pace_arg = args.pace.as_ref().unwrap();
   299→            let (coronet_key, pace) = match zjjrq_resolve_pace(heat, pace_arg) {
   300→                Some(result) => result,
   301→                None => {
   302→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}' (tried coronet and silks)", pace_arg, heat_key);
   303→                    return 1;
   304→                }
   305→            };
   306→            if let Some(tack) = pace.tacks.first() {
   307→                let state_str = zjjrq_pace_state_str(&tack.state);
   308→                println!("Pace: {} ({})", tack.silks, coronet_key);
   309→                println!("State: {}", state_str);
   310→                println!("Heat: {}", heat_key);
   311→                println!();
   312→                println!("{}", tack.text);
   313→                if let Some(ref direction) = tack.direction {
   314→                    println!();
   315→                    println!("Direction: {}", direction);
   316→                }
   317→            }
   318→        }
   319→        jjrq_ParadeFormat::Full => {
   320→            // Read paddock file content
   321→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   322→                Ok(content) => content,
   323→                Err(e) => {
   324→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   325→                    return 1;
   326→                }
   327→            };
   328→
   329→            let status_str = match heat.status {
   330→                HeatStatus::Racing => "racing",
   331→                HeatStatus::Stabled => "stabled",
   332→                HeatStatus::Retired => "retired",
   333→            };
   334→
   335→            println!("Heat: {} ({})", heat.silks, heat_key);
   336→            println!("Status: {}", status_str);
   337→            println!("Created: {}", heat.creation_time);
   338→            println!();
   339→            println!("## Paddock");
   340→            println!();
   341→            println!("{}", paddock_content);
   342→            println!();
   343→            println!("## Paces");
   344→            println!();
   345→
   346→            for coronet_key in &heat.order {
   347→                if let Some(pace) = heat.paces.get(coronet_key) {
   348→                    if let Some(tack) = pace.tacks.first() {
   349→                        // Skip complete/abandoned if --remaining
   350→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   351→                            continue;
   352→                        }
   353→                        let state_str = zjjrq_pace_state_str(&tack.state);
   354→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   355→                        println!();
   356→                        println!("{}", tack.text);
   357→                        if let Some(ref direction) = tack.direction {
   358→                            println!();
   359→                            println!("**Direction:** {}", direction);
   360→                        }
   361→                        println!();
   362→                    }
   363→                }
   364→            }
   365→        }
   366→    }
   367→
   368→    0
   369→}
   370→
   371→/// Helper to resolve pace by coronet or silks
   372→///
   373→/// First tries to parse pace_arg as a Coronet and lookup by coronet key.
   374→/// If that fails, iterates heat.paces to find a pace where tacks[0].silks matches pace_arg.
   375→/// Returns tuple of (coronet_key, pace_ref) if found.
   376→fn zjjrq_resolve_pace<'a>(
   377→    heat: &'a crate::jjrg_gallops::jjrg_Heat,
   378→    pace_arg: &str,
   379→) -> Option<(&'a String, &'a Pace)> {
   380→    // Try parsing as Coronet first
   381→    if let Ok(coronet) = Coronet::jjrf_parse(pace_arg) {
   382→        let coronet_key = coronet.jjrf_display();
   383→        if let Some((key, pace)) = heat.paces.get_key_value(&coronet_key) {
   384→            return Some((key, pace));
   385→        }
   386→    }
   387→
   388→    // Fallback: search by silks
   389→    for (coronet_key, pace) in &heat.paces {
   390→        if let Some(tack) = pace.tacks.first() {
   391→            if tack.silks == pace_arg {
   392→                return Some((coronet_key, pace));
   393→            }
   394→        }
   395→    }
   396→
   397→    None
   398→}
   399→
   400→/// Helper to convert PaceState to display string
   401→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   402→    match state {
   403→        PaceState::Rough => "rough",
   404→        PaceState::Bridled => "bridled",
   405→        PaceState::Complete => "complete",
   406→        PaceState::Abandoned => "abandoned",
   407→    }
   408→}
