   410→// ============================================================================
   411→// Retire - Extract complete Heat data for archival trophy
   412→// ============================================================================
   413→
   414→/// Arguments for retire command
   415→#[derive(Debug)]
   416→pub struct jjrq_RetireArgs {
   417→    pub file: std::path::PathBuf,
   418→    pub firemark: Firemark,
   419→}
   420→
   421→/// Output structure for retire command
   422→#[derive(Serialize)]
   423→pub(crate) struct zjjrq_RetireOutput {
   424→    pub(crate) firemark: String,
   425→    pub(crate) silks: String,
   426→    pub(crate) created: String,
   427→    pub(crate) status: String,
   428→    pub(crate) paddock_file: String,
   429→    pub(crate) paddock_content: String,
   430→    pub(crate) paces: Vec<zjjrq_RetirePace>,
   431→    // TODO: steeplechase array from jjx_rein
   432→    // steeplechase: Vec<SteeplechaseEntry>,
   433→}
   434→
   435→/// Pace structure for retire output (full tack history)
   436→#[derive(Serialize)]
   437→pub(crate) struct zjjrq_RetirePace {
   438→    pub(crate) coronet: String,
   439→    pub(crate) silks: String,
   440→    pub(crate) tacks: Vec<zjjrq_RetireTack>,
   441→}
   442→
   443→/// Tack structure for retire output
   444→#[derive(Serialize)]
   445→pub(crate) struct zjjrq_RetireTack {
   446→    pub(crate) ts: String,
   447→    pub(crate) state: String,
   448→    pub(crate) text: String,
   449→    #[serde(skip_serializing_if = "Option::is_none")]
   450→    pub(crate) direction: Option<String>,
   451→}
   452→
   453→/// Run the retire command - extract complete Heat data for archival
   454→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   455→    let gallops = match Gallops::jjrg_load(&args.file) {
   456→        Ok(g) => g,
   457→        Err(e) => {
   458→            eprintln!("jjx_retire: error: {}", e);
   459→            return 1;
   460→        }
   461→    };
   462→
   463→    let heat_key = args.firemark.jjrf_display();
   464→    let heat = match gallops.heats.get(&heat_key) {
   465→        Some(h) => h,
   466→        None => {
   467→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   468→            return 1;
   469→        }
   470→    };
   471→
   472→    // Read paddock file content
   473→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   474→        Ok(content) => content,
   475→        Err(e) => {
   476→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   477→            return 1;
   478→        }
   479→    };
   480→
   481→    // Build paces array with full tack history, ordered per Heat's order array
   482→    let mut paces = Vec::new();
   483→    for coronet_key in &heat.order {
   484→        if let Some(pace) = heat.paces.get(coronet_key) {
   485→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   486→                zjjrq_RetireTack {
   487→                    ts: tack.ts.clone(),
   488→                    state: match tack.state {
   489→                        PaceState::Rough => "rough".to_string(),
   490→                        PaceState::Bridled => "bridled".to_string(),
   491→                        PaceState::Complete => "complete".to_string(),
   492→                        PaceState::Abandoned => "abandoned".to_string(),
   493→                    },
   494→                    text: tack.text.clone(),
   495→                    direction: tack.direction.clone(),
   496→                }
   497→            }).collect();
   498→
   499→            paces.push(zjjrq_RetirePace {
   500→                coronet: coronet_key.clone(),
   501→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   502→                tacks,
   503→            });
   504→        }
   505→    }
   506→
   507→    let output = zjjrq_RetireOutput {
   508→        firemark: heat_key.clone(),
   509→        silks: heat.silks.clone(),
   510→        created: heat.creation_time.clone(),
   511→        status: match heat.status {
   512→            HeatStatus::Racing => "racing".to_string(),
   513→            HeatStatus::Stabled => "stabled".to_string(),
   514→            HeatStatus::Retired => "retired".to_string(),
   515→        },
   516→        paddock_file: heat.paddock_file.clone(),
   517→        paddock_content,
   518→        paces,
   519→        // TODO: Call jjx_rein internally to get steeplechase entries
   520→    };
   521→
   522→    // Output JSON
   523→    match serde_json::to_string_pretty(&output) {
   524→        Ok(json) => {
   525→            println!("{}", json);
   526→            0
   527→        }
   528→        Err(e) => {
   529→            eprintln!("jjx_retire: error serializing output: {}", e);
   530→            1
   531→        }
   532→    }
   533→}
